def solve(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape

    # Find the two non-zero colors
    colors = set(np.unique(grid)) - {0}
    colors = sorted(colors)
    if len(colors) != 2:
        return grid.tolist()
    A, B = colors

    # Step 1: Identify defects (0-cells with >=3 same-color non-zero 4-neighbors)
    defects = []  # (r, c, region_color)
    for r in range(H):
        for c in range(W):
            if grid[r,c] == 0:
                neighbor_counts = {}
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] != 0:
                        v = int(grid[nr,nc])
                        neighbor_counts[v] = neighbor_counts.get(v, 0) + 1
                # Check if any non-zero color has >=3 neighbors
                for color, count in neighbor_counts.items():
                    if count >= 3:
                        defects.append((r, c, color))
                        break

    # Step 2: Create output from input
    output = grid.copy()

    # Step 3: Erase strays (non-zero cells with >=3 zero 4-neighbors)
    for r in range(H):
        for c in range(W):
            if grid[r,c] != 0:
                zero_count = 0
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W:
                        if grid[nr,nc] == 0:
                            zero_count += 1
                if zero_count >= 3:
                    output[r,c] = 0

    # Step 4: Paint 3x3 blocks around defects
    for r, c, region_color in defects:
        other_color = B if region_color == A else A
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < H and 0 <= nc < W:
                    output[nr,nc] = other_color
        output[r,c] = 8

    return output.tolist()

# Test on both examples
